const response = $json;
const candidate = response.candidates?.[0];
const parts = candidate?.content?.parts || [];

const rawText = parts
  .filter((part) => typeof part.text === 'string')
  .map((part) => part.text)
  .join('\n')
  .trim();

if (!rawText) {
  throw new Error('Gemini scenario response did not include text output');
}

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```/i, '')
  .replace(/```$/i, '')
  .trim();

const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');

if (jsonStart === -1 || jsonEnd === -1 || jsonEnd < jsonStart) {
  throw new Error('Gemini scenario response did not contain a complete JSON object');
}

const raw = cleaned.slice(jsonStart, jsonEnd + 1);

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error(`Failed to parse scenario JSON: ${error.message}`);
}

const input = $('Build Production Input').first().json;
const sceneCount = Number(input.scene_count || 8);

const sceneVideoPrompts = Array.isArray(parsed.scene_video_prompts) ? parsed.scene_video_prompts : [];
const stillImagePrompts = Array.isArray(parsed.still_image_prompts) ? parsed.still_image_prompts : [];
const youtubeTags = Array.isArray(parsed.youtube_tags)
  ? parsed.youtube_tags
  : (Array.isArray(input.youtube_tags) ? input.youtube_tags : []);

const lastSceneVideoPrompt = sceneVideoPrompts.length ? sceneVideoPrompts[sceneVideoPrompts.length - 1] : '';
const lastStillImagePrompt = stillImagePrompts.length ? stillImagePrompts[stillImagePrompts.length - 1] : '';

const normalizedSceneVideoPrompts = Array.from({ length: sceneCount }, (_, index) => {
  return sceneVideoPrompts[index]
    || lastSceneVideoPrompt
    || `${input.topic} 장면 ${index + 1}, 세로형 실사 시네마틱 영상, 텍스트 없음, 워터마크 없음`;
});

const normalizedStillImagePrompts = Array.from({ length: sceneCount }, (_, index) => {
  return stillImagePrompts[index]
    || lastStillImagePrompt
    || `${input.topic} 장면 ${index + 1}, 세로형 실사 포토리얼 이미지, 텍스트 없음, 워터마크 없음`;
});

return {
  json: {
    ...input,
    scenario_title: parsed.scenario_title || input.topic,
    duration_seconds: Number(input.target_duration_seconds || input.duration_seconds || 60),
    youtube_title: parsed.youtube_title || input.youtube_title,
    youtube_description: parsed.youtube_description || input.youtube_description,
    youtube_tags: youtubeTags,
    narration_script: parsed.narration_script || input.topic,
    scene_video_prompts: normalizedSceneVideoPrompts,
    still_image_prompts: normalizedStillImagePrompts,
  },
};

