const script = $('Parse Scenario').first().json.narration_script || '';
 const chunks = script.split(/(?<=[.!?])\s+/).filter(Boolean);
 const totalDuration = Number($('Parse Scenario').first().json.duration_seconds || 60);
 const secondsPerChunk = Math.max(2, Math.floor(totalDuration / Math.max(chunks.length, 1)));

 const toSrtTime = (seconds) => {
   const date = new Date(seconds * 1000).toISOString().slice(11, 23);
   return date.replace('.', ',');
 };

 const lines = [];
 for (let index = 0; index < chunks.length; index++) {
   const start = index * secondsPerChunk;
   const end = Math.min(totalDuration, start + secondsPerChunk);
   lines.push(String(index + 1));
   lines.push(`${toSrtTime(start)} --> ${toSrtTime(end)}`);
   lines.push(chunks[index]);
   lines.push('');
 }

 return {
   json: {
     subtitle_content: lines.join('\n')
   }
 };

const scenario = $('Parse Scenario').first().json;

  const sceneCount = Number(
