const binary = $binary ?? {};
const image = binary.image;

const parseFileSize = (value) => {
  if (typeof value === 'number') return value;
  if (typeof value !== 'string') return 0;

  const match = value.trim().match(/^([\d.]+)\s*(B|bytes|KB|MB|GB|KiB|MiB|GiB)?$/i);
  if (!match) return 0;

  const amount = Number(match[1]);
  const unit = (match[2] || 'B').toLowerCase();

  if (unit === 'gb' || unit === 'gib') return Math.round(amount * 1024 * 1024 * 1024);
  if (unit === 'mb' || unit === 'mib') return Math.round(amount * 1024 * 1024);
  if (unit === 'kb' || unit === 'kib') return Math.round(amount * 1024);
  return Math.round(amount);
};

